-- ===== ch02t3s1 Shapes & Nodes of Orbitals =====
('axai_ch02_121', 'The shape of an s orbital is:', 'mcq', '["spherical","dumbbell","cloverleaf","planar"]', 'spherical', 'easy', 1, 'both', 'An s orbital is spherically symmetrical about the nucleus.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_122', 'The shape of a p orbital is:', 'mcq', '["spherical","dumbbell-shaped","cloverleaf","linear"]', 'dumbbell-shaped', 'easy', 2, 'both', 'A p orbital has two lobes giving a dumbbell shape.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_123', 'The number of nodal planes in a p orbital is:', 'mcq', '["0","1","2","3"]', '1', 'easy', 2, 'both', 'A p orbital (l = 1) has one nodal plane passing through the nucleus.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_124', 'The number of angular nodes (nodal planes) in an s orbital is:', 'mcq', '["0","1","2","3"]', '0', 'easy', 2, 'both', 'For an s orbital l = 0, so it has no angular nodes.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_125', 'The number of orbitals (orientations) in a p subshell is:', 'mcq', '["1","3","5","7"]', '3', 'easy', 1, 'both', 'A p subshell has three orbitals: pₓ, p_y and p_z.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_126', 'Most d orbitals have the shape described as:', 'mcq', '["spherical","dumbbell","four lobes (cloverleaf)","linear"]', 'four lobes (cloverleaf)', 'easy', 2, 'both', 'Four of the five d orbitals have a four-lobed cloverleaf shape.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_127', 'The total number of nodes in an orbital is given by:', 'mcq', '["n","n − 1","n − l","l"]', 'n − 1', 'easy', 3, 'both', 'Total nodes = (radial) + (angular) = (n − l − 1) + l = n − 1.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_128', 'The number of angular nodes in an orbital equals:', 'mcq', '["n − 1","l","n − l − 1","n"]', 'l', 'easy', 3, 'both', 'The number of angular nodes equals the azimuthal quantum number l.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_129', 'The number of radial nodes in the 1s orbital is:', 'mcq', '["0","1","2","3"]', '0', 'easy', 2, 'both', 'Radial nodes = n − l − 1 = 1 − 0 − 1 = 0.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_130', 'Which type of orbital is spherically symmetrical?', 'mcq', '["s","p","d","f"]', 's', 'easy', 1, 'both', 'Only s orbitals are spherically symmetrical.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_131', 'The number of radial nodes in a 3s orbital is:', 'mcq', '["0","1","2","3"]', '2', 'medium', 4, 'both', 'Radial nodes = n − l − 1 = 3 − 0 − 1 = 2.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_132', 'The number of radial nodes in a 2p orbital is:', 'mcq', '["0","1","2","3"]', '0', 'medium', 4, 'both', 'Radial nodes = n − l − 1 = 2 − 1 − 1 = 0.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_133', 'The number of angular nodes in a 3d orbital is:', 'mcq', '["0","1","2","3"]', '2', 'medium', 4, 'both', 'Angular nodes = l = 2 for a d orbital.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_134', 'The total number of nodes in a 3p orbital is:', 'mcq', '["1","2","3","4"]', '2', 'medium', 4, 'both', 'Total nodes = n − 1 = 3 − 1 = 2.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_135', 'The number of radial nodes in a 4s orbital is:', 'mcq', '["1","2","3","4"]', '3', 'medium', 5, 'both', 'Radial nodes = n − l − 1 = 4 − 0 − 1 = 3.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_136', 'The number of radial nodes in a 3d orbital is:', 'mcq', '["0","1","2","3"]', '0', 'medium', 5, 'both', 'Radial nodes = n − l − 1 = 3 − 2 − 1 = 0.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_137', 'The number of nodal planes in a d orbital such as d_xy is:', 'mcq', '["0","1","2","3"]', '2', 'medium', 4, 'both', 'A d orbital (l = 2) has two nodal planes.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_138', 'Which orbital has exactly 1 radial node and 1 angular node?', 'mcq', '["2p","3s","3p","3d"]', '3p', 'medium', 6, 'both', '3p: radial = 3 − 1 − 1 = 1 and angular = l = 1.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_139', 'The total number of nodes in a 4d orbital is:', 'mcq', '["2","3","4","5"]', '3', 'medium', 4, 'both', 'Total nodes = n − 1 = 4 − 1 = 3.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_140', 'The number of radial nodes in a 4p orbital is:', 'mcq', '["1","2","3","4"]', '2', 'medium', 5, 'both', 'Radial nodes = n − l − 1 = 4 − 1 − 1 = 2.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_141', 'An orbital has 2 radial nodes and 1 angular node. The orbital is:', 'mcq', '["3p","4p","4d","3d"]', '4p', 'hard', 7, 'jee', 'angular = l = 1 (p) and radial = n − l − 1 = 2 → n = 4, so 4p.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_142', 'The number of radial nodes in a 5f orbital is:', 'mcq', '["0","1","2","3"]', '1', 'hard', 7, 'jee', 'Radial nodes = n − l − 1 = 5 − 3 − 1 = 1.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_143', 'The total number of nodes in a 3d orbital is:', 'mcq', '["1","2","3","4"]', '2', 'hard', 6, 'jee', 'Total nodes = n − 1 = 2 (0 radial + 2 angular).', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_144', 'Which orbital has zero radial nodes and zero angular nodes?', 'mcq', '["1s","2s","2p","3s"]', '1s', 'hard', 6, 'jee', 'For 1s, radial = 1 − 0 − 1 = 0 and angular = l = 0.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_145', 'An orbital with principal quantum number 4 and 2 angular nodes is:', 'mcq', '["4s","4p","4d","4f"]', '4d', 'hard', 6, 'jee', '2 angular nodes mean l = 2 (d); with n = 4 it is 4d.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_146', 'The number of radial nodes in a 6s orbital is:', 'mcq', '["3","4","5","6"]', '5', 'hard', 7, 'jee', 'Radial nodes = n − l − 1 = 6 − 0 − 1 = 5.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_147', 'For a 4d orbital, the numbers of radial and angular nodes respectively are:', 'mcq', '["1 and 2","2 and 1","0 and 2","2 and 2"]', '1 and 2', 'hard', 7, 'jee', 'Radial = 4 − 2 − 1 = 1; angular = l = 2.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_148', 'Which of the following orbitals has the maximum number of radial nodes?', 'mcq', '["3s","3p","4s","4p"]', '4s', 'hard', 8, 'jee', 'Radial nodes: 3s = 2, 3p = 1, 4s = 3, 4p = 2 → 4s has the most.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_149', 'The number of angular nodes in an f orbital is:', 'mcq', '["1","2","3","4"]', '3', 'hard', 6, 'jee', 'Angular nodes = l = 3 for an f orbital.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
('axai_ch02_150', 'An orbital has a total of 3 nodes, of which 1 is angular. The orbital is:', 'mcq', '["4s","4p","4d","3d"]', '4p', 'hard', 8, 'jee', 'Total = n − 1 = 3 → n = 4; angular = l = 1 (p) → 4p.', 'chem', 'ch02', 'ch02t3', 'ch02t3s1'),
-- ===== ch02t3s2 Dual Nature — de Broglie & Heisenberg =====
('axai_ch02_151', 'The de Broglie wavelength of a particle is given by:', 'mcq', '["λ = h·mv","λ = h/mv","λ = mv/h","λ = hv/m"]', 'λ = h/mv', 'easy', 2, 'both', 'de Broglie: λ = h/p = h/(mv).', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_152', 'According to de Broglie, the wavelength of a particle is inversely proportional to its:', 'mcq', '["mass only","velocity only","momentum","energy squared"]', 'momentum', 'easy', 2, 'both', 'λ = h/p, so wavelength is inversely proportional to momentum.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_153', 'Heisenberg''s uncertainty principle relates the uncertainties in:', 'mcq', '["energy and time only","position and momentum","mass and velocity","charge and spin"]', 'position and momentum', 'easy', 2, 'both', 'It states that position and momentum cannot both be known exactly at the same time.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_154', 'The dual (wave and particle) nature of matter was proposed by:', 'mcq', '["Bohr","Heisenberg","de Broglie","Pauli"]', 'de Broglie', 'easy', 1, 'neet', 'de Broglie proposed that matter also has an associated wavelength.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_155', 'Heisenberg''s uncertainty principle is expressed as:', 'mcq', '["Δx·Δp ≥ h/4π","Δx·Δp ≤ h/4π","Δx·Δp = h","Δx·Δp ≥ 4πh"]', 'Δx·Δp ≥ h/4π', 'easy', 2, 'both', 'The product of the uncertainties is at least h/4π.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_156', 'Matter waves are significant only for:', 'mcq', '["large everyday objects","particles of very small mass such as electrons","stationary objects","charged objects only"]', 'particles of very small mass such as electrons', 'easy', 3, 'both', 'Because λ = h/mv, only very small masses give measurable wavelengths.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_157', 'As the velocity of a particle increases, its de Broglie wavelength:', 'mcq', '["increases","decreases","stays the same","becomes zero"]', 'decreases', 'easy', 2, 'both', 'λ = h/mv, so higher velocity gives shorter wavelength.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_158', 'For particles moving at the same speed, the de Broglie wavelength is largest for the:', 'mcq', '["electron","proton","neutron","alpha particle"]', 'electron', 'easy', 3, 'both', 'The electron has the smallest mass, so λ = h/mv is largest.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_159', 'The wave nature of electrons was experimentally confirmed by the:', 'mcq', '["Millikan oil-drop experiment","Davisson and Germer experiment","Rutherford scattering experiment","Thomson experiment"]', 'Davisson and Germer experiment', 'easy', 2, 'neet', 'Electron diffraction in the Davisson–Germer experiment confirmed matter waves.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_160', 'The minimum value of the product of the uncertainties in position and momentum is about:', 'mcq', '["h","h/2π","h/4π","4πh"]', 'h/4π', 'easy', 2, 'both', 'Δx·Δp ≥ h/4π.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_161', 'The de Broglie wavelength of an electron (mass 9.1×10⁻³¹ kg) moving at 2×10⁶ m/s is approximately (h = 6.6×10⁻³⁴ J·s):', 'mcq', '["0.036 Å","0.36 Å","3.6 Å","36 Å"]', '3.6 Å', 'medium', 5, 'jee', 'λ = 6.6×10⁻³⁴ / (9.1×10⁻³¹ × 2×10⁶) ≈ 3.6×10⁻¹⁰ m = 3.6 Å.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_162', 'The de Broglie wavelength of an electron accelerated through 100 V is approximately:', 'mcq', '["0.123 Å","1.23 Å","12.3 Å","123 Å"]', '1.23 Å', 'medium', 5, 'jee', 'λ = 12.27/√V Å = 12.27/√100 = 1.23 Å.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_163', 'If the velocity of a particle is doubled, its de Broglie wavelength becomes:', 'mcq', '["doubled","halved","four times","unchanged"]', 'halved', 'medium', 4, 'both', 'λ ∝ 1/v, so doubling v halves λ.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_164', 'The de Broglie wavelength of a 1 kg body moving at 1 m/s is of the order of:', 'mcq', '["10⁻³⁴ m","10⁻¹⁰ m","10⁻⁷ m","1 m"]', '10⁻³⁴ m', 'medium', 4, 'both', 'λ = 6.6×10⁻³⁴ / (1 × 1) ≈ 10⁻³⁴ m — far too small to detect.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_165', 'For two particles having equal kinetic energy, the one with larger mass has a de Broglie wavelength that is:', 'mcq', '["larger","smaller","equal","zero"]', 'smaller', 'medium', 5, 'jee', 'λ = h/√(2mKE); for fixed KE, larger m gives smaller λ.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_166', 'For a proton and an electron moving with the same velocity, the de Broglie wavelength of the proton is:', 'mcq', '["larger","smaller","equal","zero"]', 'smaller', 'medium', 4, 'both', 'The proton has much greater mass, so λ = h/mv is smaller.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_167', 'An electron and a proton have the same de Broglie wavelength. Which has the greater velocity?', 'mcq', '["the electron","the proton","both equal","cannot be determined"]', 'the electron', 'medium', 6, 'jee', 'For equal λ, mv is equal; the lighter electron must move faster.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_168', 'The minimum uncertainty in the position of an electron, given the uncertainty in its momentum, is found from:', 'mcq', '["Δx ≥ h/(4π·Δp)","Δx ≥ 4πh/Δp","Δx ≥ Δp/h","Δx ≥ h·Δp"]', 'Δx ≥ h/(4π·Δp)', 'medium', 4, 'both', 'Rearranging Δx·Δp ≥ h/4π gives Δx ≥ h/(4π·Δp).', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_169', 'The de Broglie wavelength of an electron accelerated through 400 V is approximately:', 'mcq', '["0.31 Å","0.61 Å","1.23 Å","6.1 Å"]', '0.61 Å', 'medium', 5, 'jee', 'λ = 12.27/√400 = 12.27/20 ≈ 0.61 Å.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_170', 'If the kinetic energy of a particle becomes 4 times its original value, its de Broglie wavelength becomes:', 'mcq', '["doubled","halved","quartered","unchanged"]', 'halved', 'medium', 5, 'jee', 'λ ∝ 1/√KE; four times KE halves the wavelength.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_171', 'The de Broglie wavelength of an electron with kinetic energy 50 eV is approximately:', 'mcq', '["0.87 Å","1.74 Å","3.5 Å","12.3 Å"]', '1.74 Å', 'hard', 7, 'jee', 'λ = 12.27/√(KE in eV) = 12.27/√50 ≈ 1.74 Å.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_172', 'The uncertainty in velocity of an electron (mass 9.1×10⁻³¹ kg) confined within 1 Å is at least about (h = 6.6×10⁻³⁴ J·s):', 'mcq', '["5.8×10⁴ m/s","5.8×10⁵ m/s","5.8×10⁶ m/s","5.8×10⁷ m/s"]', '5.8×10⁵ m/s', 'hard', 8, 'jee', 'Δv ≥ h/(4π·m·Δx) = 6.6×10⁻³⁴ / (4π × 9.1×10⁻³¹ × 10⁻¹⁰) ≈ 5.8×10⁵ m/s.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_173', 'A proton and an alpha particle are accelerated through the same potential difference. The ratio of their de Broglie wavelengths (λ_proton : λ_alpha) is:', 'mcq', '["√2 : 1","2√2 : 1","2 : 1","4 : 1"]', '2√2 : 1', 'hard', 8, 'jee', 'λ ∝ 1/√(mq); λ_p/λ_α = √(m_α q_α / m_p q_p) = √(4×2) = 2√2.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_174', 'The de Broglie wavelength of the electron in the first Bohr orbit of hydrogen is equal to:', 'mcq', '["the radius of the orbit","the circumference of the orbit","half the circumference","the diameter of the orbit"]', 'the circumference of the orbit', 'hard', 7, 'jee', 'Bohr''s condition 2πr = nλ with n = 1 gives λ = 2πr, the circumference.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_175', 'The momentum of a particle whose de Broglie wavelength is 6.6 Å is (h = 6.6×10⁻³⁴ J·s):', 'mcq', '["1×10⁻²⁵ kg·m/s","1×10⁻²⁴ kg·m/s","1×10⁻²³ kg·m/s","1×10⁻²⁸ kg·m/s"]', '1×10⁻²⁴ kg·m/s', 'hard', 7, 'jee', 'p = h/λ = 6.6×10⁻³⁴ / 6.6×10⁻¹⁰ = 1×10⁻²⁴ kg·m/s.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_176', 'For an electron, if the uncertainty in position equals its de Broglie wavelength, the minimum uncertainty in momentum is:', 'mcq', '["p/4π","p/2π","4πp","p"]', 'p/4π', 'hard', 8, 'jee', 'Δp ≥ h/(4π·Δx) with Δx = λ = h/p gives Δp ≥ p/4π.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_177', 'A ball of mass 0.1 kg moves at 10 m/s. Its de Broglie wavelength (h = 6.6×10⁻³⁴ J·s) is:', 'mcq', '["6.6×10⁻³⁰ m","6.6×10⁻³² m","6.6×10⁻³³ m","6.6×10⁻³⁴ m"]', '6.6×10⁻³⁴ m', 'hard', 6, 'jee', 'λ = h/mv = 6.6×10⁻³⁴ / (0.1 × 10) = 6.6×10⁻³⁴ m.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_178', 'The de Broglie wavelength of an electron accelerated through a potential of 9 V is approximately:', 'mcq', '["1.36 Å","4.09 Å","12.27 Å","36.8 Å"]', '4.09 Å', 'hard', 7, 'jee', 'λ = 12.27/√9 = 12.27/3 ≈ 4.09 Å.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_179', 'Two electrons A and B have de Broglie wavelengths in the ratio 2 : 1. The ratio of their kinetic energies (E_A : E_B) is:', 'mcq', '["1 : 2","2 : 1","1 : 4","4 : 1"]', '1 : 4', 'hard', 8, 'jee', 'E ∝ 1/λ², so E_A : E_B = (1/2)² : 1 = 1 : 4.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2'),
('axai_ch02_180', 'The kinetic energy of an electron whose de Broglie wavelength is 1 Å is approximately:', 'mcq', '["1.5 eV","15 eV","150 eV","1500 eV"]', '150 eV', 'hard', 8, 'jee', 'From λ = 12.27/√V Å, √V = 12.27 → V ≈ 150, so KE ≈ 150 eV.', 'chem', 'ch02', 'ch02t3', 'ch02t3s2')
on conflict (id) do nothing;
